import java.util.Arrays;
public class Main {
    public static void main(String[] args) {
        Order.resetCounter();
        Restaurant r = new Restaurant("X", 1);
        r.addMenuItem(new MenuItem("Pasta", 100.00, "Mains"));
        Table t = r.assignTable("A");
        Order o = r.placeOrder(t.getNumber(), Arrays.asList("Pasta"));
        double total = r.bill(o, new DineInBilling(10));
        if (Math.abs(total - 110.00) < 0.01) System.out.println("BILL_OK");
        if ("PAID".equals(o.getState())) System.out.println("PAID_OK");
    }
}

